{
  "name": "CoachingPass Custom Interview Solution",
  "description": "A comprehensive AI-powered interview preparation tool that generates deep research reports, Q&A scripts, and tailored strategies based on user documents."
}

export interface UserInputData {
  companyName: string;
  jobTitle: string;
  interviewType: string;
  studentName: string;
  resumeFile: File | null;
  coverLetterFile: File | null;
  interviewNoticeFile: File | null;
  jobPostingFile: File | null;
}

export enum ProcessStep {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING', // Deep Research
  DRAFTING = 'DRAFTING', // Writing Content
  DESIGNING = 'DESIGNING', // Generating Cover
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface GeneratedContent {
  reportText: string;
  coverImageUrl: string;
}

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string usable by Gemini
 */
const fileToInlineData = async (file: File) => {
  return new Promise<{ mimeType: string; data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g., "data:application/pdf;base64,")
      const base64Data = base64String.split(',')[1];
      resolve({
        mimeType: file.type,
        data: base64Data,
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Performs deep research and drafts the interview guide.
 * Uses gemini-3-pro-preview with thinking config.
 */
export const generateInterviewReport = async (
  company: string,
  job: string,
  type: string,
  name: string,
  files: { resume: File | null; cover: File | null; notice: File | null; posting: File | null }
): Promise<string> => {

  const contentParts: any[] = [];

  // Add Files
  if (files.resume) contentParts.push({ inlineData: await fileToInlineData(files.resume) });
  if (files.cover) contentParts.push({ inlineData: await fileToInlineData(files.cover) });
  if (files.notice) contentParts.push({ inlineData: await fileToInlineData(files.notice) });
  if (files.posting) contentParts.push({ inlineData: await fileToInlineData(files.posting) });

  // Prompt Construction
  const prompt = `
    당신은 대한민국 최고의 면접 코칭 전문가입니다. 
    아래 제공된 서류(이력서, 자소서, 공고, 안내문)와 정보를 바탕으로 '${name}' 지원자를 위한 '${company}' 기업의 '${job}' 직무 맞춤형 면접 솔루션을 작성하세요.

    [필수 포함 내용]
    1. 서류 기반 적중률 높은 예상 질문 & 고득점 답변 스크립트 (최소 20개). 질문의 의도와 답변 포인트(STAR 기법 등)를 상세히 포함할 것.
    2. 예상치 못한 압박 질문이나 돌발 질문이 나왔을 때의 구체적인 임기응변 전략 및 마인드셋.
    3. 면접관의 시선(채용 담당자 관점)에서 지원자가 현재 서류상 부족해 보이는 점과 이를 방어하기 위해 꼭 대비해야 할 부분.
    4. 면접장에서 면접관에게 확실히 점수를 따고 합격 시그널을 유도할 수 있는 고득점 행동/화법 노하우.

    [작성 규칙]
    - 분량: 매우 상세하고 방대하게 작성하여 A4 30페이지 분량에 육박하는 깊이 있는 내용을 출력할 것. 
    - 톤앤매너: 전문적이고, 논리적이며, 격려하는 어조.
    - 마크다운 문법(---, ** 등)은 최소화하여 가독성 있게 작성할 것.
    - 면접 유형: '${type}'에 맞춰 시뮬레이션 할 것.
  `;

  contentParts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Capable of reasoning
      contents: { parts: contentParts },
      config: {
        thinkingConfig: { thinkingBudget: 16000 }, // Allocate specific budget for deep research simulation
      },
    });

    return response.text || "리포트 생성에 실패했습니다.";
  } catch (error) {
    console.error("Text Generation Error:", error);
    throw new Error("면접 리포트 생성 중 오류가 발생했습니다.");
  }
};

/**
 * Generates the cover image using Gemini Nano Banana Pro 3.0 (gemini-3-pro-image-preview).
 */
export const generateCoverImage = async (company: string, job: string): Promise<string> => {
  try {
    const prompt = `
      A professional, minimalist corporate report cover design.
      High quality, 4k resolution.
      The background should be a subtle, trustworthy corporate blue and white geometric pattern.
      In the center, elegant typography in Korean reads: "${company} ${job} 솔루션".
      No other text. Clean, modern aesthetic suitable for a high-end consulting firm.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
            aspectRatio: "3:4", // Document aspect ratio
            imageSize: "2K"
        }
      },
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("이미지 데이터가 없습니다.");

  } catch (error) {
    console.error("Image Generation Error:", error);
    // Return a placeholder if generation fails to avoid breaking flow
    return "https://picsum.photos/600/800"; 
  }
};

/**
 * Since we cannot easily npm install 'docx' and 'file-saver' in a purely generated response 
 * that needs to run in a limited environment immediately, we will use a robust HTML-to-Word 
 * export strategy. This ensures the output is downloadable and formatted correctly as a Word doc
 * with the image and text provided.
 */

import { GeneratedContent } from "../types";

export const downloadAsWord = (content: GeneratedContent, filename: string) => {
  const header = `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' 
          xmlns:w='urn:schemas-microsoft-com:office:word' 
          xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
      <meta charset='utf-8'>
      <title>${filename}</title>
      <style>
        body { font-family: 'Malgun Gothic', sans-serif; line-height: 1.6; }
        .cover-page { text-align: center; page-break-after: always; display: flex; flex-direction: column; justify-content: center; height: 100vh; }
        .cover-img { max-width: 100%; max-height: 80vh; object-fit: contain; }
        h1 { color: #1e3a8a; font-size: 24pt; margin-top: 20px; }
        h2 { color: #1e40af; font-size: 18pt; margin-top: 15px; border-bottom: 2px solid #1e40af; padding-bottom: 5px; }
        h3 { color: #334155; font-size: 14pt; margin-top: 10px; }
        p { margin-bottom: 10px; font-size: 11pt; text-align: justify; }
        .section { margin-bottom: 30px; }
      </style>
    </head>
    <body>
  `;

  const coverPage = `
    <div class="cover-page">
      <img src="${content.coverImageUrl}" class="cover-img" alt="Cover Image" />
      <h1>${filename}</h1>
    </div>
  `;

  // Convert plain text newlines to HTML paragraphs for better Word formatting
  const formattedBody = content.reportText
    .split('\n')
    .map(line => line.trim() === '' ? '<br/>' : `<p>${line}</p>`)
    .join('');

  const bodyContent = `
    <div class="content-body">
      ${formattedBody}
    </div>
  `;

  const footer = "</body></html>";

  const sourceHTML = header + coverPage + bodyContent + footer;

  const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);

  const fileDownload = document.createElement("a");
  document.body.appendChild(fileDownload);
  fileDownload.href = source;
  fileDownload.download = `${filename}.doc`;
  fileDownload.click();
  document.body.removeChild(fileDownload);
};

import React from 'react';
import { ProcessStep } from '../types';

interface ProcessVisualizerProps {
  currentStep: ProcessStep;
}

const steps = [
  { id: ProcessStep.ANALYZING, label: 'Gemini Deep Research (심층 분석)', icon: '🔍' },
  { id: ProcessStep.DRAFTING, label: '솔루션 작성 (30p+)', icon: '📝' },
  { id: ProcessStep.DESIGNING, label: 'Nano Banana Pro 표지 생성', icon: '🎨' },
  { id: ProcessStep.COMPLETED, label: '완료 및 다운로드', icon: '✅' },
];

export const ProcessVisualizer: React.FC<ProcessVisualizerProps> = ({ currentStep }) => {
  const getStepStatus = (stepId: ProcessStep, index: number) => {
    const stepOrder = [ProcessStep.IDLE, ProcessStep.ANALYZING, ProcessStep.DRAFTING, ProcessStep.DESIGNING, ProcessStep.COMPLETED];
    const currentIndex = stepOrder.indexOf(currentStep);
    const stepIndex = stepOrder.indexOf(stepId);

    if (currentStep === ProcessStep.ERROR) return 'text-red-400';
    if (currentIndex > stepIndex) return 'text-blue-600 font-bold';
    if (currentIndex === stepIndex) return 'text-blue-600 font-bold animate-pulse';
    return 'text-gray-300';
  };

  const getBarColor = (index: number) => {
     const stepOrder = [ProcessStep.IDLE, ProcessStep.ANALYZING, ProcessStep.DRAFTING, ProcessStep.DESIGNING, ProcessStep.COMPLETED];
     const currentIndex = stepOrder.indexOf(currentStep);
     if (currentIndex > index) return 'bg-blue-600';
     return 'bg-gray-200';
  };

  return (
    <div className="w-full max-w-4xl mx-auto py-8">
      <div className="flex items-center justify-between relative">
        {/* Connector Lines */}
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 -z-10 flex px-10">
           {steps.slice(0, -1).map((_, idx) => (
             <div key={`line-${idx}`} className={`flex-1 h-1 mx-2 transition-colors duration-500 ${getBarColor(idx + 1)} rounded`}></div>
           ))}
        </div>

        {steps.map((step, idx) => (
          <div key={step.id} className="flex flex-col items-center bg-white px-2">
            <div className={`w-12 h-12 rounded-full border-4 flex items-center justify-center text-2xl bg-white transition-all duration-300 ${
              getStepStatus(step.id, idx).includes('blue') ? 'border-blue-600 scale-110 shadow-lg' : 'border-gray-200'
            }`}>
              {step.icon}
            </div>
            <span className={`mt-2 text-sm font-medium transition-colors duration-300 ${getStepStatus(step.id, idx)}`}>
              {step.label}
            </span>
          </div>
        ))}
      </div>

      {currentStep !== ProcessStep.IDLE && currentStep !== ProcessStep.COMPLETED && currentStep !== ProcessStep.ERROR && (
         <div className="mt-6 text-center text-blue-800 bg-blue-50 p-3 rounded-lg animate-fade-in">
            <p className="text-sm font-medium">
                AI가 작업을 진행 중입니다. 잠시만 기다려주세요... <br/>
                (최대 1~2분 소요될 수 있습니다)
            </p>
         </div>
      )}
    </div>
  );
};

import React, { useState, ChangeEvent } from 'react';
import { UserInputData } from '../types';

interface InputFormProps {
  onSubmit: (data: UserInputData) => void;
  isProcessing: boolean;
}

export const InputForm: React.FC<InputFormProps> = ({ onSubmit, isProcessing }) => {
  const [formData, setFormData] = useState<UserInputData>({
    companyName: '',
    jobTitle: '',
    interviewType: '직무/인성 통합 면접',
    studentName: '',
    resumeFile: null,
    coverLetterFile: null,
    interviewNoticeFile: null,
    jobPostingFile: null,
  });

  const handleTextChange = (e: ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e: ChangeEvent<HTMLInputElement>) => {
    const { name, files } = e.target;
    if (files && files.length > 0) {
      setFormData(prev => ({ ...prev, [name]: files[0] }));
    }
