import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { InputForm } from './components/InputForm';
import { ProcessVisualizer } from './components/ProcessVisualizer';
import { ProcessStep, UserInputData, GeneratedContent } from './types';
import { generateCoverImage, generateInterviewReport } from './services/geminiService';
import { downloadAsWord } from './services/documentService';

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessStep>(ProcessStep.IDLE);
  const [content, setContent] = useState<GeneratedContent | null>(null);
  const [userData, setUserData] = useState<UserInputData | null>(null);

  const handleStartAnalysis = async (data: UserInputData) => {
    setUserData(data);
    setStep(ProcessStep.ANALYZING);

    try {
      // 1. Deep Research & Drafting
      console.log("Starting Deep Research...");
      // Simulate separate steps for UI effect, although text generation happens in one go usually
      // Or we can generate them. For this demo, we do the heavy lifting in one call 
      // but update UI to show "Drafting" after a delay or during the process if we were streaming.

      const reportText = await generateInterviewReport(
        data.companyName,
        data.jobTitle,
        data.interviewType,
        data.studentName,
        {
          resume: data.resumeFile,
          cover: data.coverLetterFile,
          notice: data.interviewNoticeFile,
          posting: data.jobPostingFile
        }
      );

      setStep(ProcessStep.DRAFTING);

      // Simulate drafting time for UX (since API returns full text at once if not streaming)
      // In a real app with streaming, we'd update this based on chunks.
      await new Promise(resolve => setTimeout(resolve, 1500)); 

      setStep(ProcessStep.DESIGNING);

      // 2. Generate Cover Image
      const coverImageUrl = await generateCoverImage(data.companyName, data.jobTitle);

      setContent({
        reportText,
        coverImageUrl
      });

      setStep(ProcessStep.COMPLETED);

    } catch (error) {
      console.error(error);
      setStep(ProcessStep.ERROR);
      alert("솔루션 생성 중 오류가 발생했습니다. 다시 시도해주세요.");
    }
  };

  const handleDownload = () => {
    if (content && userData) {
      downloadAsWord(content, `${userData.companyName}_${userData.jobTitle}_면접솔루션_${userData.studentName}`);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-blue-600 w-8 h-8 rounded-lg flex items-center justify-center text-white font-bold">C</div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">코칭패스 <span className="text-blue-600 font-medium">면접 맞춤 솔루션</span></h1>
          </div>
          <div className="text-xs text-slate-500 font-medium bg-slate-100 px-3 py-1 rounded-full">
            Powered by Gemini Deep Research
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-6 py-10">

        {/* Stepper */}
        <div className="mb-12">
          <ProcessVisualizer currentStep={step} />
        </div>

        {/* Dynamic Content based on Step */}
        {step === ProcessStep.IDLE && (
           <div className="animate-fade-in-up">
             <InputForm onSubmit={handleStartAnalysis} isProcessing={false} />
           </div>
        )}

        {(step === ProcessStep.ANALYZING || step === ProcessStep.DRAFTING || step === ProcessStep.DESIGNING) && (
          <div className="flex flex-col items-center justify-center py-20 animate-pulse">
            <div className="w-24 h-24 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-6"></div>
            <h3 className="text-xl font-bold text-slate-700">AI가 데이터를 분석하고 있습니다</h3>
            <p className="text-slate-500 mt-2">수십만 건의 데이터를 대조하여 최적의 답변을 생성 중입니다...</p>
          </div>
        )}

        {step === ProcessStep.COMPLETED && content && (
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden animate-fade-in-up border border-slate-200">
            <div className="grid grid-cols-1 md:grid-cols-3">
              {/* Preview Image */}
              <div className="bg-slate-100 p-8 flex items-center justify-center border-b md:border-b-0 md:border-r border-slate-200">
                <div className="relative w-full aspect-[3/4] shadow-2xl rounded-lg overflow-hidden transform hover:scale-105 transition duration-500">
                    <img src={content.coverImageUrl} alt="Cover" className="object-cover w-full h-full" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                    <div className="absolute bottom-4 left-4 text-white">
                        <p className="text-xs opacity-75">Generated by Nano Banana Pro</p>
                    </div>
                </div>
              </div>

              {/* Success Info & Action */}
