};

interface FileInputProps {
  label: string;
  name: string;
  onChange: (e: ChangeEvent<HTMLInputElement>) => void;
  file: File | null;
}

const FileInput: React.FC<FileInputProps> = ({ label, name, onChange, file }) => (
  <div className={`relative p-5 rounded-xl border-2 border-dashed transition-all duration-300 group ${file ? 'border-green-400 bg-green-50/50' : 'border-slate-200 hover:border-blue-400 hover:bg-blue-50/30'}`}>
    <label className="block text-sm font-bold text-slate-700 mb-1 group-hover:text-blue-700 transition-colors cursor-pointer w-full h-full">
        {label}
        <input
            type="file"
            name={name}
            onChange={onChange}
            className="hidden"
            accept=".pdf,.doc,.docx,.txt,.jpg,.png"
        />
        <div className="flex items-center mt-2">
            {file ? (
                <div className="flex items-center text-green-600 text-sm">
                     <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                     <span className="truncate max-w-[200px]">{file.name}</span>
                </div>
