                <div className="flex items-center text-slate-400 text-xs font-medium">
                     <span className="px-2 py-1 bg-slate-100 rounded text-slate-500 mr-2 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">파일 선택</span>
                     <span>선택된 파일 없음</span>
                </div>
            )}
        </div>
    </label>
  </div>
);

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { InputForm } from './components/InputForm';
import { ProcessVisualizer } from './components/ProcessVisualizer';
import { ProcessStep, UserInputData, GeneratedContent } from './types';
import { generateCoverImage, generateInterviewReport } from './services/geminiService';
import { downloadAsWord } from './services/documentService';

// Declaration for the AI Studio helper injected by the environment
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessStep>(ProcessStep.IDLE);
  const [content, setContent] = useState<GeneratedContent | null>(null);
  const [userData, setUserData] = useState<UserInputData | null>(null);
  const [hasApiKey, setHasApiKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (window.aistudio) {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(selected);
    }
  };

  const handleApiKeySelect = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      await checkApiKey();
    }
  };

  const handleStartAnalysis = async (data: UserInputData) => {
    if (!hasApiKey && window.aistudio) {
       await handleApiKeySelect();
       // Re-check
       const selected = await window.aistudio.hasSelectedApiKey();
       if (!selected) return;
    }

    setUserData(data);
    setStep(ProcessStep.ANALYZING);

    try {
      // 1. Deep Research & Drafting
      console.log("Starting Deep Research...");

      const reportText = await generateInterviewReport(
        data.companyName,
        data.jobTitle,
        data.interviewType,
        data.studentName,
        {
          resume: data.resumeFile,
          cover: data.coverLetterFile,
          notice: data.interviewNoticeFile,
          posting: data.jobPostingFile
        }
      );

      setStep(ProcessStep.DRAFTING);

      // Simulate drafting time for UX
      await new Promise(resolve => setTimeout(resolve, 1500)); 

      setStep(ProcessStep.DESIGNING);

      // 2. Generate Cover Image
      const coverImageUrl = await generateCoverImage(data.companyName, data.jobTitle);

      setContent({
        reportText,
        coverImageUrl
      });

      setStep(ProcessStep.COMPLETED);

    } catch (error) {
      console.error(error);
      setStep(ProcessStep.ERROR);
      alert("솔루션 생성 중 오류가 발생했습니다. API Key를 확인하거나 잠시 후 다시 시도해주세요.");
    }
  };

  const handleDownload = () => {
    if (content && userData) {
      downloadAsWord(content, `${userData.companyName}_${userData.jobTitle}_면접솔루션_${userData.studentName}`);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-slate-200 pb-20 font-sans selection:bg-amber-500/30 selection:text-amber-200">
      {/* Header */}
      <header className="bg-black/80 backdrop-blur-md border-b border-white/10 sticky top-0 z-50 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => window.location.reload()}>
            <div className="w-10 h-10 bg-gradient-to-br from-amber-200 to-amber-600 rounded-xl flex items-center justify-center text-black group-hover:scale-105 transition-transform duration-300 shadow-[0_0_15px_rgba(245,158,11,0.3)]">
                {/* Key Icon */}
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
                </svg>
            </div>
            <div className="flex flex-col">
                <h1 className="text-xl font-extrabold text-white tracking-tight leading-none">코칭패스</h1>
                <span className="text-[10px] font-bold text-amber-500 tracking-[0.2em] uppercase mt-1">Premium Interview Solution</span>
            </div>
          </div>

          <div className="flex items-center space-x-4">
            <div className="hidden md:flex items-center space-x-2 text-xs font-medium text-slate-400 bg-white/5 px-4 py-2 rounded-full border border-white/10">
                <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-amber-500"></span>
                </span>
                <span>Powered by Gemini Deep Research</span>
            </div>

            <button 
                onClick={handleApiKeySelect}
                className="text-xs font-bold text-black bg-amber-500 hover:bg-amber-400 px-4 py-2 rounded-lg transition-colors shadow-[0_0_10px_rgba(245,158,11,0.4)] flex items-center gap-2"
            >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" /></svg>
                {hasApiKey ? 'API Key 변경' : 'API Key 설정'}
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-6 py-12">

        {/* Hero Section - Visible mainly on IDLE */}
        {step === ProcessStep.IDLE && (
            <div className="text-center mb-16 animate-fade-in-down">
                <span className="inline-block py-1 px-4 rounded-full bg-amber-900/30 border border-amber-500/30 text-amber-400 text-xs font-bold mb-8 shadow-[0_0_20px_rgba(245,158,11,0.1)]">
                    VVIP 합격 솔루션
                </span>
                <h2 className="text-4xl md:text-5xl lg:text-7xl font-extrabold text-white mb-8 tracking-tight leading-tight">
                    합격의 문을 여는<br/>
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-amber-200 via-amber-400 to-amber-600 drop-shadow-sm">마스터키 (Master Key)</span>
                </h2>
                <p className="text-lg md:text-xl text-slate-400 max-w-2xl mx-auto leading-relaxed font-light">
                    단순한 코칭이 아닙니다.<br className="hidden md:block"/> 
                    <strong className="text-white">코칭패스</strong>는 당신의 서류를 완벽하게 분석하여<br/>
                    면접관을 압도할 수 있는 <span className="text-amber-400">유일무이한 전략</span>을 제시합니다.
                </p>
            </div>
        )}

        {/* Stepper */}
        <div className={`transition-all duration-700 ease-in-out transform ${step === ProcessStep.IDLE ? 'mb-12 translate-y-0 opacity-100' : 'mb-20 translate-y-0 opacity-100'}`}>
          <ProcessVisualizer currentStep={step} />
        </div>

        {/* Dynamic Content based on Step */}
        {step === ProcessStep.IDLE && (
           <div className="animate-fade-in-up delay-100 relative z-10">
             <InputForm onSubmit={handleStartAnalysis} isProcessing={false} />
           </div>
        )}

        {(step === ProcessStep.ANALYZING || step === ProcessStep.DRAFTING || step === ProcessStep.DESIGNING) && (
          <div className="flex flex-col items-center justify-center py-24 animate-fade-in">
            <div className="relative mb-12">
                <div className="w-40 h-40 border-2 border-amber-900/50 rounded-full animate-ping absolute top-0 left-0"></div>
                <div className="w-40 h-40 border-2 border-amber-500/20 border-t-amber-500 rounded-full animate-spin relative z-10 bg-black/40 backdrop-blur-sm shadow-[0_0_30px_rgba(245,158,11,0.2)]"></div>
                <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-5xl animate-bounce">
                    🔑
                </div>
            </div>
            <h3 className="text-3xl font-bold text-white mb-3">Master Key Forging...</h3>
            <p className="text-amber-400/80 text-lg">AI가 합격의 열쇠를 만들고 있습니다</p>
            <p className="text-slate-500 text-sm mt-4">최대 30페이지 분량의 심층 리포트 생성 중 (약 2~3분 소요)</p>
          </div>
        )}

        {step === ProcessStep.COMPLETED && content && (
          <div className="bg-[#111] rounded-3xl shadow-2xl overflow-hidden animate-fade-in-up border border-white/10 relative">
            {/* Background Glow */}
            <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-amber-500/5 rounded-full blur-3xl -z-10 pointer-events-none"></div>

            <div className="grid grid-cols-1 lg:grid-cols-3">
              {/* Preview Image */}
              <div className="bg-[#050505] p-10 flex items-center justify-center border-b lg:border-b-0 lg:border-r border-white/10 relative overflow-hidden group">
                <div className="relative w-full max-w-sm aspect-[3/4] shadow-[0_20px_50px_-12px_rgba(0,0,0,0.5)] rounded-sm overflow-hidden transform group-hover:scale-105 transition duration-700 ease-out border border-white/5">
                    <img src={content.coverImageUrl} alt="Cover" className="object-cover w-full h-full" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-90"></div>
                    <div className="absolute bottom-8 left-8 text-white text-left">
                         <div className="w-10 h-1 bg-amber-500 mb-4 shadow-[0_0_10px_rgba(245,158,11,0.5)]"></div>
                         <p className="text-3xl font-serif tracking-tight mb-2 leading-tight">{userData?.jobTitle}</p>
                         <p className="text-sm text-amber-100/80 font-light tracking-wide uppercase">{userData?.companyName} INTERVIEW SOLUTION</p>
                    </div>
                </div>
              </div>

              {/* Success Info & Action */}
              <div className="col-span-2 p-10 lg:p-16 flex flex-col justify-center text-left">
                <div className="mb-10">
                   <div className="inline-flex items-center px-3 py-1 rounded-full bg-green-900/30 text-green-400 text-xs font-bold mb-6 border border-green-500/30">
                        <svg className="w-3 h-3 mr-1.5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd"/></svg>
                        COMPLETE
                   </div>
                   <h2 className="text-3xl md:text-5xl font-bold text-white mb-6 leading-tight">
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-amber-300 to-amber-600">{userData?.studentName}</span>님,<br/>
                    준비는 끝났습니다.
                   </h2>
                   <p className="text-slate-400 text-lg leading-relaxed font-light">
                     {userData?.companyName} {userData?.jobTitle} 직무 합격을 위한 <br/>
                     가장 강력한 무기가 준비되었습니다.
                   </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-12">
                    <div className="p-6 bg-white/5 rounded-2xl border border-white/5 flex items-start space-x-4 hover:bg-white/10 transition-colors group">
                         <div className="flex-shrink-0 w-10 h-10 bg-amber-500/10 rounded-lg flex items-center justify-center text-amber-500 font-bold border border-amber-500/20 group-hover:border-amber-500/50 transition-colors">Q</div>
                         <div>
                            <h4 className="font-bold text-slate-200">예상 질문 적중률 99%</h4>
                            <p className="text-sm text-slate-500 mt-1">서류 기반 심층 분석 완료</p>
                         </div>
                    </div>
                    <div className="p-6 bg-white/5 rounded-2xl border border-white/5 flex items-start space-x-4 hover:bg-white/10 transition-colors group">
