import React from 'react';
import { ProcessStep } from '../types';

interface ProcessVisualizerProps {
  currentStep: ProcessStep;
}

const steps = [
  { id: ProcessStep.ANALYZING, label: 'Gemini Deep Research', icon: '🔍' },
  { id: ProcessStep.DRAFTING, label: '솔루션 작성 (30p+)', icon: '📝' },
  { id: ProcessStep.DESIGNING, label: 'Premium 표지 생성', icon: '🎨' },
  { id: ProcessStep.COMPLETED, label: '완료 및 다운로드', icon: '✅' },
];

export const ProcessVisualizer: React.FC<ProcessVisualizerProps> = ({ currentStep }) => {
  const getStepStatus = (stepId: ProcessStep, index: number) => {
    const stepOrder = [ProcessStep.IDLE, ProcessStep.ANALYZING, ProcessStep.DRAFTING, ProcessStep.DESIGNING, ProcessStep.COMPLETED];
    const currentIndex = stepOrder.indexOf(currentStep);
    const stepIndex = stepOrder.indexOf(stepId);

    if (currentStep === ProcessStep.ERROR) return 'text-red-500';
    if (currentIndex > stepIndex) return 'text-amber-500 font-bold';
    if (currentIndex === stepIndex) return 'text-amber-500 font-bold animate-pulse';
    return 'text-slate-600';
  };

  const getBarColor = (index: number) => {
     const stepOrder = [ProcessStep.IDLE, ProcessStep.ANALYZING, ProcessStep.DRAFTING, ProcessStep.DESIGNING, ProcessStep.COMPLETED];
     const currentIndex = stepOrder.indexOf(currentStep);
     if (currentIndex > index) return 'bg-amber-500';
     return 'bg-slate-800';
  };

  return (
    <div className="w-full max-w-4xl mx-auto py-8">
      <div className="flex items-center justify-between relative">
        {/* Connector Lines */}
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 -z-10 flex px-10">
           {steps.slice(0, -1).map((_, idx) => (
             <div key={`line-${idx}`} className={`flex-1 h-0.5 mx-2 transition-colors duration-500 ${getBarColor(idx + 1)} rounded`}></div>
           ))}
        </div>

        {steps.map((step, idx) => (
          <div key={step.id} className="flex flex-col items-center px-2 relative">
            <div className={`w-12 h-12 rounded-full border-2 flex items-center justify-center text-xl transition-all duration-300 bg-[#0a0a0a] z-10 ${
              getStepStatus(step.id, idx).includes('amber') ? 'border-amber-500 text-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.4)] scale-110' : 'border-slate-700 text-slate-700'
            }`}>
              {step.icon}
            </div>
            <span className={`mt-3 text-xs font-medium transition-colors duration-300 ${getStepStatus(step.id, idx)}`}>
              {step.label}
            </span>
          </div>
        ))}
      </div>

      {currentStep !== ProcessStep.IDLE && currentStep !== ProcessStep.COMPLETED && currentStep !== ProcessStep.ERROR && (
         <div className="mt-8 text-center text-amber-400 bg-amber-900/10 border border-amber-500/20 p-3 rounded-lg animate-fade-in max-w-md mx-auto">
            <p className="text-sm font-medium">
                AI가 데이터를 정밀 분석 중입니다. <br/>
                (고품질 리포트 생성을 위해 시간이 소요됩니다)
            </p>
         </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
// We create a function to get the client because the API key might change if the user selects one.
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string usable by Gemini
 */
const fileToInlineData = async (file: File) => {
  return new Promise<{ mimeType: string; data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g., "data:application/pdf;base64,")
      const base64Data = base64String.split(',')[1];
      resolve({
        mimeType: file.type,
        data: base64Data,
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Performs deep research and drafts the interview guide.
 * Uses gemini-3-pro-preview with thinking config.
 */
export const generateInterviewReport = async (
  company: string,
  job: string,
  type: string,
  name: string,
  files: { resume: File | null; cover: File | null; notice: File | null; posting: File | null }
): Promise<string> => {

  const contentParts: any[] = [];
  const ai = getAiClient();

  // Add Files
  if (files.resume) contentParts.push({ inlineData: await fileToInlineData(files.resume) });
  if (files.cover) contentParts.push({ inlineData: await fileToInlineData(files.cover) });
  if (files.notice) contentParts.push({ inlineData: await fileToInlineData(files.notice) });
  if (files.posting) contentParts.push({ inlineData: await fileToInlineData(files.posting) });

  // Prompt Construction
  const prompt = `
    당신은 대한민국 상위 1%를 위한 프리미엄 면접 코칭 전문가 '코칭패스'의 수석 컨설턴트입니다.
    아래 제공된 서류(이력서, 자소서, 공고, 안내문)와 정보를 바탕으로 '${name}' 지원자를 위한 '${company}' 기업의 '${job}' 직무 맞춤형 면접 솔루션을 작성하세요.

    [작성 절대 규칙 - 어길 시 오류로 간주됨]
    1. **마크다운 문법 사용 금지**: (**굵게**, ##헤더, ---구분선, - 리스트 등) 마크다운 문법을 절대 사용하지 마십시오. 오직 텍스트로만 작성하십시오.
    2. **문단 간격**: 가독성을 위해 두 줄(문장)마다 한 번씩 줄바꿈(엔터 2번)을 하여 빈 줄을 만드십시오. 빽빽한 글이 되지 않도록 하십시오.
    3. **방대한 분량**: 최소 A4 30페이지 분량이 나올 수 있도록 아주 상세하고 깊이 있게 작성하십시오. (글자 수 약 20,000자 이상 목표).
    4. **어조**: 매우 전문적이고 냉철하면서도 지원자에게 확신을 주는 고급스러운 컨설팅 어조를 유지하십시오.

    [필수 포함 내용]
    1. **서류 심층 분석**: 제출된 이력서와 자소서의 강점과 치명적인 약점을 채용 담당자의 시선에서 적나라하게 분석하십시오.
    2. **직무 맞춤 예상 질문 & 답변 (30문항 이상)**: 
       - 직무 역량 질문, 인성 질문, 로열티 질문 등을 망라하십시오.
       - 각 질문별 '질문 의도', '답변 전략(STAR)', '모범 답변 스크립트'를 상세히 작성하십시오.
    3. **압박 면접 & 돌발 상황 방어 로직**:
       - 지원자의 약점을 파고드는 예상 압박 질문 시나리오와 이를 유연하게 대처하는 화법.
    4. **필승 합격 시그널**:
       - 면접관에게 점수를 따는 비언어적 태도, 마지막 할 말, 입장/퇴장 매너 등 디테일한 팁.
    5. **면접 유형별 시뮬레이션**: '${type}' 유형에 맞춘 구체적인 시뮬레이션 가이드.
  `;

  contentParts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', 
      contents: { parts: contentParts },
      config: {
        thinkingConfig: { thinkingBudget: 24000 }, // Increased budget for longer output
      },
    });

    let text = response.text || "리포트 생성에 실패했습니다.";

    // Add Footer programmatically to ensure it exists
    const footer = `


    ------------------------------------------------------------------------------
    [COACHING PASS COPYRIGHT NOTICE]
    본 솔루션은 코칭패스 AI 엔진에 의해 생성되었습니다. 
    사용된 모든 개인정보 및 서류 데이터는 솔루션 생성 즉시 시스템에서 영구 파기되었습니다.
    본 자료의 저작권은 코칭패스에 있으며, 무단 배포를 금합니다.
    ------------------------------------------------------------------------------
    `;

    return text + footer;

  } catch (error) {
    console.error("Text Generation Error:", error);
    throw new Error("면접 리포트 생성 중 오류가 발생했습니다.");
  }
};

/**
 * Generates the cover image using Gemini Nano Banana Pro 3.0 (gemini-3-pro-image-preview).
 */
export const generateCoverImage = async (company: string, job: string): Promise<string> => {
  const ai = getAiClient();
  try {
    const prompt = `
      A premium, ultra-luxury book cover design.
      Theme: High-end Black and Gold business aesthetics. 
      Composition: Minimalist but powerful. Use abstract golden geometric lines on a deep matte black background.
      Center Text: "${company}" and "${job}" in elegant, high-contrast serif Korean typography.
      Atmosphere: Professional, trustworthy, exclusive, corporate consulting.
      Quality: 8k resolution, photorealistic textures of gold foil stamping on black paper.
      Ratio: Vertical portrait.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
            aspectRatio: "3:4", // Closest supported vertical ratio to 2:3 for documents
            imageSize: "2K"
        }
      },
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("이미지 데이터가 없습니다.");

  } catch (error) {
    console.error("Image Generation Error:", error);
    return "https://images.unsplash.com/photo-1634152962476-4b8a00e1915c?q=80&w=1287&auto=format&fit=crop"; 
  }
};

import { GeneratedContent } from "../types";

export const downloadAsWord = (content: GeneratedContent, filename: string) => {
  const header = `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' 
          xmlns:w='urn:schemas-microsoft-com:office:word' 
          xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
      <meta charset='utf-8'>
      <title>${filename}</title>
      <style>
        body { font-family: 'Malgun Gothic', 'Dotum', sans-serif; line-height: 1.8; color: #000; }
        .cover-page { text-align: center; page-break-after: always; display: flex; flex-direction: column; justify-content: center; height: 100vh; align-items: center; background-color: #000; color: #fff; }
        .cover-img { max-width: 100%; max-height: 80vh; object-fit: contain; margin-bottom: 20px; border: 2px solid #d4af37; }
        .title-area { margin-top: 30px; color: #d4af37; }
        h1 { font-size: 28pt; font-weight: bold; margin: 0; }

        /* Content Body Styles */
        .content-body { padding: 40px; }
        p { margin-bottom: 12px; font-size: 11pt; text-align: justify; word-break: break-all; }
      </style>
    </head>
    <body>
  `;

  const coverPage = `
    <div class="cover-page">
      <img src="${content.coverImageUrl}" class="cover-img" alt="Cover Image" />
      <div class="title-area">
        <h1>${filename}</h1>
      </div>
    </div>
  `;

  // Convert plain text newlines to HTML paragraphs. 
  // Double newlines from the model become distinct paragraphs.
  const formattedBody = content.reportText
    .split('\n')
    .map(line => {
        if (!line.trim()) return '<br/>'; // Maintain spacing
        return `<p>${line}</p>`;
    })
    .join('');

  const bodyContent = `
    <div class="content-body">
      ${formattedBody}
    </div>
  `;

  const footer = "</body></html>";

  const sourceHTML = header + coverPage + bodyContent + footer;

  const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);

  const fileDownload = document.createElement("a");
  document.body.appendChild(fileDownload);
  fileDownload.href = source;
  fileDownload.download = `${filename}.doc`;
  fileDownload.click();
  document.body.removeChild(fileDownload);
};

