          resume: data.resumeFile,
          cover: data.coverLetterFile,
          notice: data.interviewNoticeFile,
          posting: data.jobPostingFile
        }
      );

      setStep(ProcessStep.DRAFTING);

      // Simulate drafting time for UX
      await new Promise(resolve => setTimeout(resolve, 1500)); 

      setStep(ProcessStep.DESIGNING);

      // 2. Generate Cover Image
      const coverImageUrl = await generateCoverImage(data.companyName, data.jobTitle);

      setContent({
