        .footer-notice {
            margin-top: 100px;
            text-align: center;
            font-size: 10pt;
            color: #666;
            border-top: 1px solid #ccc;
            padding-top: 20px;
        }
      </style>
    </head>
    <body>
  `;

  const coverPage = `
    <div class="CoverPage">
        <div class="cover-container">
            <div class="logo-area">
                <!-- Simple CSS representation of the logo since we cannot access external images easily in a generated doc without hosting -->
                <div style="font-size: 20pt; font-weight: bold;">합격의 열쇠</div>
                <div style="font-size: 40pt; font-weight: 900;">코칭패스</div>
