                <div class="label">TARGET COMPANY</div>
                <div class="value">${userData.companyName}</div>

                <div class="label">JOB TITLE</div>
                <div class="value">${userData.jobTitle}</div>

                <div class="label">APPLICANT NAME</div>
                <div class="value">${userData.studentName}</div>
            </div>
