    </div>
    <br clear="all" style="page-break-before:always" />
  `;

  const formatText = (text: string) => {
      return text.split('\n').map(line => {
          if (!line.trim()) return '<br/>';
          return `<p>${line}</p>`;
      }).join('');
  };

  const bodyContent = `
    <div class="content-body">
      <h1>Chapter 1. 서류 기반 예상질문 & 답변</h1>
      ${formatText(content.section1)}

