import { GoogleGenAI } from "@google/genai";

// Initialize Gemini Client
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const SUPPORTED_MIME_TYPES = [
  'application/pdf',
  'text/plain',
  'text/html',
  'text/markdown',
  'text/csv',
  'text/xml',
  'text/rtf',
  'application/json',
  'image/png',
  'image/jpeg',
  'image/webp',
  'image/heic',
  'image/heif',
  // MS Word
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  // MS PowerPoint
  'application/vnd.ms-powerpoint',
  'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  // HWP (Hancom)
  'application/x-hwp',
  'application/haansofthwp',
  'application/vnd.hancom.hwp',
  'application/hwp',
  'application/haansofthwpx',
  'application/vnd.hancom.hwpx'
];

/**
 * Validates if the file type is supported by Gemini API.
 */
const validateFile = (file: File) => {
  // Check against supported whitelist
  // Note: While we allow these MIME types, Gemini's ability to process binary HWP/DOCX via inlineData 
  // depends on the model's current capabilities. 
  // If the file extension matches but the mime type varies, we try to be permissive here.

  const isSupported = SUPPORTED_MIME_TYPES.some(type => file.type.includes(type)) || 
                      SUPPORTED_MIME_TYPES.includes(file.type) ||
                      // Fallback for HWP/HWPX which often have varying mime types or empty strings in some browsers
                      file.name.endsWith('.hwp') || 
                      file.name.endsWith('.hwpx') ||
                      file.name.endsWith('.doc') || 
                      file.name.endsWith('.docx') ||
                      file.name.endsWith('.ppt') || 
                      file.name.endsWith('.pptx');

  if (!isSupported) {
    throw new Error(`지원되지 않는 파일 형식입니다 (${file.type}).\n'${file.name}'은(는) 업로드할 수 없습니다.`);
  }
};

/**
 * Converts a File object to a Base64 string usable by Gemini
 */
const fileToInlineData = async (file: File) => {
  validateFile(file); // Validate before processing

  return new Promise<{ mimeType: string; data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];

      // Ensure we send a valid mimeType even if the browser detects it poorly for HWP
      let mimeType = file.type;
      if (!mimeType || mimeType === '') {
          if (file.name.endsWith('.hwp')) mimeType = 'application/x-hwp';
          if (file.name.endsWith('.hwpx')) mimeType = 'application/haansofthwpx';
      }

      resolve({
        mimeType: mimeType,
        data: base64Data,
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates a specific section of the interview report.
 */
export const generateReportSection = async (
  sectionIndex: number,
  company: string,
  job: string,
  type: string,
  name: string,
  files: { resume: File | null; cover: File | null; notice: File | null; posting: File | null; preTask: File | null; ptMaterial: File | null }
): Promise<string> => {

  const contentParts: any[] = [];
  const ai = getAiClient();

  // Add Files to Context
  try {
    if (files.resume) contentParts.push({ inlineData: await fileToInlineData(files.resume) });
    if (files.cover) contentParts.push({ inlineData: await fileToInlineData(files.cover) });
    if (files.notice) contentParts.push({ inlineData: await fileToInlineData(files.notice) });
    if (files.posting) contentParts.push({ inlineData: await fileToInlineData(files.posting) });
    if (files.preTask) contentParts.push({ inlineData: await fileToInlineData(files.preTask) });
    if (files.ptMaterial) contentParts.push({ inlineData: await fileToInlineData(files.ptMaterial) });
  } catch (validationError) {
    throw validationError;
  }

  let specificPrompt = "";

  switch (sectionIndex) {
    case 1:
      specificPrompt = `
        1. **서류 기반 적중률 높은 예상질문 & 고득점 답변 스크립트 (20문항)**
        - 지원자의 서류(이력서, 자소서, 사전과제, PT자료)를 샅샅이 분석하여 나올 수 있는 모든 예상 질문을 20개 뽑으십시오.
        - 직무 역량(40%), 인성/협업(30%), 로열티/지원동기(30%) 비율로 구성하세요.
        - 만약 PT 발표자료가 제공되었다면, 해당 자료의 내용과 논리에 대한 질문도 반드시 포함시키세요.
        - 각 질문마다 [질문 의도], [답변 전략], [모범 답변 스크립트]를 작성하세요.
        - [모범 답변 스크립트]는 실제 말하는 구어체로 작성하며, 두 줄이 넘어갈 경우 반드시 줄바꿈(엔터)을 하여 가독성을 높이세요.
