import { GoogleGenAI } from "@google/genai";
import mammoth from "mammoth";

// Initialize Gemini Client
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const SUPPORTED_MIME_TYPES = [
  'application/pdf',
  'text/plain',
  'text/html',
  'text/markdown',
  'text/csv',
  'text/xml',
  'text/rtf',
  'application/json',
  'image/png',
  'image/jpeg',
  'image/webp',
  'image/heic',
  'image/heif'
];

/**
 * Validates if the file type is supported.
 * Now supports DOCX by extraction.
 */
const validateFile = (file: File) => {
  // 1. Check strict whitelist for supported MIME types (Native Gemini Support)
  const isMimeSupported = SUPPORTED_MIME_TYPES.some(type => file.type === type || file.type.startsWith(type.replace('*', '')));

  // 2. Fallback check for PDF if browser mime detection fails but extension is pdf
  const isPdfByName = file.name.toLowerCase().endsWith('.pdf');

  // 3. Check for DOCX (Supported via text extraction)
  const isDocx = file.name.toLowerCase().endsWith('.docx');

  if (isMimeSupported || isPdfByName || isDocx) {
      return;
  }

  // 4. Provide specific error messages for unsupported types
  const fileName = file.name.toLowerCase();

  if (fileName.endsWith('.doc')) {
      throw new Error(`구형 Word 파일(.doc)은 지원되지 않습니다.\n.docx로 저장하거나 [PDF로 저장] 후 업로드해주세요.`);
  }

  if (fileName.endsWith('.ppt') || fileName.endsWith('.pptx') || file.type.includes('powerpoint') || file.type.includes('presentation')) {
      throw new Error(`PPT 파일(.ppt, .pptx)은 AI가 직접 읽을 수 없습니다.\n번거로우시겠지만 [PDF로 저장] 후 업로드해주세요.`);
  }

  if (fileName.endsWith('.hwp') || fileName.endsWith('.hwpx') || file.type.includes('hwp')) {
      throw new Error(`한글 파일(.hwp)은 AI가 직접 읽을 수 없습니다.\n번거로우시겠지만 [PDF로 저장] 후 업로드해주세요.`);
  }

  throw new Error(`지원되지 않는 파일 형식입니다 (${file.type}).\nPDF, Word(.docx), 텍스트, 또는 이미지 파일만 지원됩니다.`);
};

/**
 * Process a file and return the appropriate Part object for Gemini.
 * - PDF/Image -> inlineData
 * - DOCX -> text extraction -> text part
 */
const processFile = async (file: File): Promise<{ inlineData?: { mimeType: string; data: string }; text?: string }> => {
  validateFile(file);

  // Handle DOCX Text Extraction
  if (file.name.toLowerCase().endsWith('.docx')) {
      try {
          const arrayBuffer = await file.arrayBuffer();
          const result = await mammoth.extractRawText({ arrayBuffer });
          return { 
              text: `[첨부파일: ${file.name}]\n${result.value}\n-------------------\n` 
          };
      } catch (e) {
          console.error("DOCX extraction failed", e);
          throw new Error(`Word 파일(${file.name}) 내용을 읽을 수 없습니다. PDF로 변환하여 업로드해주세요.`);
      }
  }

  // Handle Native Supported Types
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];

      // Ensure correct mime type for PDF if browser missed it
      let mimeType = file.type;
      if ((!mimeType || mimeType === '') && file.name.toLowerCase().endsWith('.pdf')) {
          mimeType = 'application/pdf';
      }

      resolve({
        inlineData: {
            mimeType: mimeType,
            data: base64Data,
        }
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates a specific section of the interview report.
 */
export const generateReportSection = async (
  sectionIndex: number,
  company: string,
  job: string,
  type: string,
  name: string,
  files: { resume: File | null; cover: File | null; notice: File | null; posting: File | null; preTask: File | null; ptMaterial: File | null }
): Promise<string> => {

  const contentParts: any[] = [];
  const ai = getAiClient();

  // Add Files to Context
  try {
    if (files.resume) contentParts.push(await processFile(files.resume));
    if (files.cover) contentParts.push(await processFile(files.cover));
    if (files.notice) contentParts.push(await processFile(files.notice));
    if (files.posting) contentParts.push(await processFile(files.posting));
    if (files.preTask) contentParts.push(await processFile(files.preTask));
    if (files.ptMaterial) contentParts.push(await processFile(files.ptMaterial));
  } catch (validationError) {
    throw validationError;
  }

  let specificPrompt = "";

  switch (sectionIndex) {
    case 1:
      specificPrompt = `
        1. **서류 기반 적중률 높은 예상질문 & 고득점 답변 스크립트 (20문항)**
        - 지원자의 서류(이력서, 자소서, 사전과제, PT자료)를 샅샅이 분석하여 나올 수 있는 모든 예상 질문을 20개 뽑으십시오.
        - 직무 역량(40%), 인성/협업(30%), 로열티/지원동기(30%) 비율로 구성하세요.
        - 만약 PT 발표자료가 제공되었다면, 해당 자료의 내용과 논리에 대한 질문도 반드시 포함시키세요.
        - 각 질문마다 [질문 의도], [답변 전략], [모범 답변 스크립트]를 작성하세요.
        - [모범 답변 스크립트]는 실제 말하는 구어체로 작성하며, 두 줄이 넘어갈 경우 반드시 줄바꿈(엔터)을 하여 가독성을 높이세요.
        - 분량: 매우 상세하게 A4 10페이지 이상 나올 정도로 길게 작성하십시오.
      `;
      break;
    case 2:
      specificPrompt = `
        2. **예상치 못한 질문(압박/돌발)이 나왔을 때 임기응변 전략**
        - 지원자의 약점이나 논리적 공백을 파고드는 날카로운 질문 10가지를 선정하세요.
        - 당황하지 않고 논리적으로 방어하는 '쿠션어 사용법', '논리 구조화 화법(PREP)'을 구체적인 예시와 함께 서술하세요.
        - 특히 제출된 사전과제나 PT자료가 있다면 그 부분에 대한 공격 포인트와 디펜스 논리를 상세히 적으십시오.
        - 답변하기 곤란한 상황(모르는 질문 등)에서의 대처 매뉴얼을 작성하세요.
        - 분량: 매우 상세하게 A4 10페이지 이상 나올 정도로 길게 작성하십시오. 문장은 자주 줄바꿈하세요.
      `;
      break;
    case 3:
      specificPrompt = `
        3. **면접관 시선에서 지원자님이 꼭 면접 전 대비해야 될 부분 (Checklist & PT Feedback)**
        - 채용 담당자가 서류를 보고 느꼈을 '우려 사항' 5가지를 적나라하게 지적하십시오.
        - 해당 우려를 불식시키기 위해 면접 전 반드시 다시 공부하거나 정리해야 할 개념/경험 리스트를 제공하세요.
        - 경쟁자 대비 지원자가 가질 수 있는 차별화 포인트(USP)를 어떻게 어필할지 전략을 짜십시오.

        **[중요: PT 발표자료 첨삭 및 보완 솔루션]**
        - 만약 사용자가 PT 발표자료를 제출했다면, 이 섹션의 절반 이상을 할애하여 해당 자료를 완벽하게 분석하십시오.
        - **구성 및 논리**: 장표의 흐름(Storyline)이 설득력 있는지 분석하고 수정 제안을 하십시오.
        - **디자인 및 가독성**: 텍스트 양, 배치, 시각적 요소에 대한 피드백을 제공하십시오.
        - **내용 보완**: 누락된 핵심 데이터나 추가하면 좋을 장표를 구체적으로 제안하십시오.
        - PT 발표 시 예상되는 약점과 이를 보완할 발표 스크립트 팁을 제공하십시오.

        - 분량: 매우 상세하게 A4 10페이지 이상 나올 정도로 길게 작성하십시오. 문장은 자주 줄바꿈하세요.
      `;
      break;
    case 4:
      specificPrompt = `
        4. **면접장에서 면접관에게 고득점 받을 수 있는 노하우 (Attitude & Formatting)**
        - ${type} 유형에 맞는 구체적인 입장부터 퇴장까지의 시뮬레이션.
        - 비언어적 요소(시선 처리, 자세, 목소리 톤, 제스처)에 대한 디테일한 코칭.
        - 마지막 할 말(Last Impression) 추천 멘트 3가지.
        - 면접관의 기억에 남는 '합격 시그널'을 보내는 심리학적 기법.
        - 분량: 매우 상세하게 A4 10페이지 이상 나올 정도로 길게 작성하십시오. 문장은 자주 줄바꿈하세요.
      `;
      break;
    default:
      specificPrompt = "면접 솔루션을 작성하세요.";
  }

  const prompt = `
    당신은 대한민국 상위 1% '코칭패스' 수석 컨설턴트입니다.
    지원자 '${name}'의 '${company}' '${job}' 면접 대비를 위한 심층 리포트를 작성 중입니다.

    이번 단계에서는 아래 주제에 대해서만 집중적으로 작성합니다.

    [작성 주제]
    ${specificPrompt}

    [작성 절대 규칙]
    1. **마크다운 문법 최소화**: #헤더나 **굵게** 외에 복잡한 표 등은 피하고 텍스트 위주로 작성하세요.
    2. **가독성 (중요)**: 설명이 길어지면 두 문장마다 줄바꿈을 하여 읽기 편하게 만드십시오.
    3. **전문성**: 냉철하고 분석적인 컨설턴트 어조를 유지하세요.
    4. **심층 분석**: 겉핥기식 조언이 아닌, 제공된 파일을 근거로 한 구체적인 솔루션이어야 합니다.
  `;

  contentParts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', 
      contents: { parts: contentParts },
      config: {
        thinkingConfig: { thinkingBudget: 15000 }, 
      },
    });

    return response.text || "내용 생성 실패";

  } catch (error) {
    console.error(`Section ${sectionIndex} Error:`, error);
    throw error;
  }
};

