/**
 * Generates a specific section of the interview report.
 */
export const generateReportSection = async (
  sectionIndex: number,
  company: string,
  job: string,
  type: string,
  name: string,
  files: { resume: File | null; cover: File | null; notice: File | null; posting: File | null; preTask: File | null; ptMaterial: File | null }
): Promise<string> => {

  const contentParts: any[] = [];
  const ai = getAiClient();

  try {
    if (files.resume) contentParts.push(await processFile(files.resume));
    if (files.cover) contentParts.push(await processFile(files.cover));
    if (files.notice) contentParts.push(await processFile(files.notice));
    if (files.posting) contentParts.push(await processFile(files.posting));
    if (files.preTask) contentParts.push(await processFile(files.preTask));
    if (files.ptMaterial) contentParts.push(await processFile(files.ptMaterial));
  } catch (validationError) {
    throw validationError;
  }

  let specificPrompt = "";

  switch (sectionIndex) {
    case 1:
      specificPrompt = `
        1. 서류 기반 적중률 높은 예상질문 & 고득점 답변 스크립트 (20문항)
        - 지원자의 서류(이력서, 자소서, 사전과제, PT자료)를 분석하여 예상 질문 20개를 선정.
        - 직무 역량(40%), 인성/협업(30%), 로열티/지원동기(30%) 비율.
        - 질문 의도, 답변 전략, 모범 답변 스크립트 포함.
        - 모범 답변은 구어체로 작성.
      `;
      break;
    case 2:
      specificPrompt = `
        2. 예상치 못한 질문(압박/돌발)이 나왔을 때 임기응변 전략
        - 약점이나 논리적 공백을 파고드는 날카로운 질문 10가지.
        - 쿠션어 사용법, PREP 논리 구조화 화법.
        - 곤란한 상황 대처 매뉴얼.
      `;
      break;
    case 3:
      specificPrompt = `
        3. 면접관 시선에서 지원자님이 꼭 면접 전 대비해야 될 부분 (Checklist & PT Feedback)
        - 서류상 우려 사항 5가지와 해결책.
        - 차별화 포인트(USP) 전략.
        - PT 발표자료가 있다면, 장표 흐름(Storyline), 디자인, 내용 보완점 상세 분석.
      `;
      break;
    case 4:
      specificPrompt = `
        4. 면접장에서 면접관에게 고득점 받을 수 있는 노하우 (Attitude & Formatting)
        - 입장부터 퇴장까지 시뮬레이션.
        - 비언어적 요소(시선, 자세, 목소리).
        - 마지막 할 말 추천 멘트.
      `;
      break;
    default:
      specificPrompt = "면접 솔루션을 작성하세요.";
  }

  const prompt = `
    당신은 대한민국 상위 1% '코칭패스' 수석 컨설턴트입니다.
    지원자 '${name}'의 '${company}' '${job}' 면접 대비를 위한 심층 리포트를 작성 중입니다.

    이번 단계에서는 아래 주제에 대해서만 집중적으로 작성합니다.

    [작성 주제]
    ${specificPrompt}

    [작성 절대 규칙 - 중요!!]
    1. **마크다운(Markdown) 문법을 절대 사용하지 마십시오.** 
       - 볼드체(**), 헤더(###), 리스트(-) 등의 기호를 쓰지 마십시오.
       - 오직 순수한 텍스트와 줄바꿈(엔터)만으로 가독성을 확보하십시오.
       - 제목이나 강조할 부분은 기호 없이 대괄호 [ ] 를 사용하거나 단독 줄에 배치하세요.
    2. 가독성: 설명이 길어지면 두 문장마다 줄바꿈을 하세요.
    3. 전문성: 냉철하고 분석적인 어조.
    4. 분량: 주제별로 A4 10페이지 분량이 나올 정도로 아주 상세하게 작성하세요.
  `;

  contentParts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', 
      contents: { parts: contentParts },
      config: {
        thinkingConfig: { thinkingBudget: 15000 }, 
      },
    });

    // Post-process to ensure no markdown slips through (basic cleanup)
    let text = response.text || "내용 생성 실패";
    text = text.replace(/\*\*/g, '').replace(/###/g, '').replace(/##/g, '').replace(/#/g, '');

    return text;

  } catch (error) {
    console.error(`Section ${sectionIndex} Error:`, error);
    throw error;
  }
};

import { GeneratedContent, UserInputData } from "../types";

export const downloadAsWord = (content: GeneratedContent, userData: UserInputData) => {
  const filename = `${userData.companyName}_${userData.jobTitle}_${userData.studentName}`;

  // HTML-based Word Export Structure
  const header = `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' 
          xmlns:w='urn:schemas-microsoft-com:office:word' 
          xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
      <meta charset='utf-8'>
      <title>${filename}</title>
      <style>
        /* Word Specific Page Layout */
        @page {
            size: A4;
            margin: 1.0in;
        }
        @page CoverPage {
            size: A4;
            margin: 0; /* No margin for cover to allow full bleed image */
        }
        div.CoverPage {
            page: CoverPage;
            width: 100%;
            height: 100%;
        }

        body { font-family: 'Malgun Gothic', 'Dotum', sans-serif; line-height: 1.6; color: #000; }

        /* Content Body Styles */
        .section-break { page-break-before: always; }

        /* Text styling - No markdown means we rely on simple tags */
        h1 { font-size: 20pt; font-weight: bold; color: #d4af37; border-bottom: 2px solid #000; padding-bottom: 10px; margin-top: 40px; margin-bottom: 20px; }
        p { margin-bottom: 10px; font-size: 11pt; text-align: justify; }

        .infographic {
            width: 100%;
            height: auto;
            margin-bottom: 20px;
            border: 1px solid #ddd;
        }

        .cover-img {
            width: 100%;
            height: 100%;
            object-fit: cover;
        }

        .footer-notice {
            margin-top: 100px;
            text-align: center;
            font-size: 10pt;
            color: #666;
            border-top: 1px solid #ccc;
            padding-top: 20px;
        }
      </style>
    </head>
    <body>
  `;

  // Cover Page with Image
  let coverPage = '';
  if (content.coverImage) {
      coverPage = `
        <div class="CoverPage">
            <img src="data:image/png;base64,${content.coverImage}" class="cover-img" />
        </div>
        <br clear="all" style="page-break-before:always" />
      `;
  } else {
      // Fallback if image failed
      coverPage = `
        <div class="CoverPage" style="background:black; color:white; display:flex; flex-direction:column; justify-content:center; align-items:center; text-align:center; height:100vh;">
            <h1 style="color:gold; font-size:40pt;">Coaching Pass</h1>
            <h2>${userData.companyName} - ${userData.jobTitle}</h2>
            <h3>${userData.studentName}</h3>
        </div>
        <br clear="all" style="page-break-before:always" />
      `;
  }

  const formatText = (text: string) => {
      // Convert newlines to breaks, and ensure no markdown leftovers
      return text.split('\n').map(line => {
          if (!line.trim()) return '<br/>';
          return `<p>${line}</p>`;
      }).join('');
  };

  const getSectionHTML = (title: string, text: string, imageBase64?: string) => {
      let imgHTML = '';
      if (imageBase64) {
          imgHTML = `<img src="data:image/png;base64,${imageBase64}" class="infographic" alt="${title} Infographic" />`;
      }
      return `
        <h1>${title}</h1>
        ${imgHTML}
        ${formatText(text)}
      `;
  };

  const bodyContent = `
    <div class="content-body">
      ${getSectionHTML("Chapter 1. 서류 기반 예상질문 & 답변", content.section1, content.section1Image)}

      <div class="section-break"></div>
      ${getSectionHTML("Chapter 2. 임기응변 전략", content.section2, content.section2Image)}

      <div class="section-break"></div>
      ${getSectionHTML("Chapter 3. 면접관의 시선 (Checklist)", content.section3, content.section3Image)}

      <div class="section-break"></div>
      ${getSectionHTML("Chapter 4. 고득점 합격 노하우", content.section4, content.section4Image)}

      <div class="footer-notice">
         <p>본 솔루션은 코칭패스 자체 AI를 활용해서 코칭패스의 코치진과 컨설턴트가 함께 제작한 솔루션입니다.</p>
         <p>사용된 모든 개인정보 및 서류 데이터는 솔루션 생성 즉시 시스템에서 영구 파기되었습니다.</p>
         <p>Copyright © Coaching Pass. All rights reserved.</p>
      </div>
    </div>
  `;

  const footer = "</body></html>";

  const sourceHTML = header + coverPage + bodyContent + footer;
  const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);

  const fileDownload = document.createElement("a");
  document.body.appendChild(fileDownload);
  fileDownload.href = source;
  fileDownload.download = `${filename}.doc`;
  fileDownload.click();
  document.body.removeChild(fileDownload);
};

import React from 'react';
import { ProcessStep } from '../types';

interface ProcessVisualizerProps {
  currentStep: ProcessStep;
}

const steps = [
  { id: ProcessStep.WORKFLOW_1, label: '예상 질문', icon: '1' },
  { id: ProcessStep.WORKFLOW_2, label: '돌발 전략', icon: '2' },
  { id: ProcessStep.WORKFLOW_3, label: '약점 분석', icon: '3' },
  { id: ProcessStep.WORKFLOW_4, label: '합격 노하우', icon: '4' },
  { id: ProcessStep.GENERATING_IMAGES, label: '표지 및 인포그래픽', icon: '🎨' },
];

export const ProcessVisualizer: React.FC<ProcessVisualizerProps> = ({ currentStep }) => {
  const stepOrder = [
      ProcessStep.IDLE, 
      ProcessStep.ANALYZING, 
      ProcessStep.WORKFLOW_1, 
      ProcessStep.WORKFLOW_2, 
      ProcessStep.WORKFLOW_3, 
      ProcessStep.WORKFLOW_4, 
      ProcessStep.GENERATING_IMAGES,
      ProcessStep.COMPLETED
  ];

  const getStepStatus = (stepId: ProcessStep, index: number) => {
    const currentIndex = stepOrder.indexOf(currentStep);
    const stepIndex = stepOrder.indexOf(stepId);

    if (currentStep === ProcessStep.ERROR) return 'text-red-500';
    if (currentIndex > stepIndex) return 'text-amber-500 font-bold';
    if (currentIndex === stepIndex) return 'text-amber-500 font-bold animate-pulse';
    return 'text-slate-600';
  };

  const getBarColor = (index: number) => {
     const currentIndex = stepOrder.indexOf(currentStep);
     // steps array indices align with WORKFLOW_1 to GENERATING_IMAGES
     // stepOrder: 0=IDLE, 1=ANALYZING, 2=WF1, 3=WF2, 4=WF3, 5=WF4, 6=IMAGES, 7=COMPLETED
     // steps[0] is WF1 (index 2 in order).
     // Visualizer connector logic:
     const targetStepIndexInOrder = index + 3; // Look ahead to next step logic

     if (currentIndex >= targetStepIndexInOrder) return 'bg-amber-500';
     return 'bg-slate-800';
  };

  return (
    <div className="w-full max-w-4xl mx-auto py-8">
      <div className="flex items-center justify-between relative">
        {/* Connector Lines */}
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 -z-10 flex px-10">
           {steps.slice(0, -1).map((_, idx) => (
             <div key={`line-${idx}`} className={`flex-1 h-0.5 mx-2 transition-colors duration-500 ${getBarColor(idx)} rounded`}></div>
           ))}
        </div>

        {steps.map((step, idx) => (
          <div key={step.id} className="flex flex-col items-center px-2 relative">
            <div className={`w-12 h-12 rounded-full border-2 flex items-center justify-center text-xl transition-all duration-300 bg-[#0a0a0a] z-10 ${
              getStepStatus(step.id, idx).includes('amber') ? 'border-amber-500 text-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.4)] scale-110' : 'border-slate-700 text-slate-700'
            }`}>
              {step.icon}
            </div>
            <span className={`mt-3 text-xs font-medium transition-colors duration-300 ${getStepStatus(step.id, idx)}`}>
              {step.label}
            </span>
          </div>
        ))}
      </div>

      {currentStep !== ProcessStep.IDLE && currentStep !== ProcessStep.COMPLETED && currentStep !== ProcessStep.ERROR && (
         <div className="mt-8 text-center text-amber-400 bg-amber-900/10 border border-amber-500/20 p-3 rounded-lg animate-fade-in max-w-md mx-auto">
            <p className="text-sm font-medium">
                {currentStep === ProcessStep.GENERATING_IMAGES 
                    ? "표지 디자인 및 챕터별 인포그래픽을 생성 중입니다..." 
                    : "AI가 각 챕터별로 심층 리포트를 작성 중입니다. (약 3분 소요)"}
            </p>
         </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { InputForm } from './components/InputForm';
import { ProcessVisualizer } from './components/ProcessVisualizer';
import { ProcessStep, UserInputData, GeneratedContent } from './types';
import { generateReportSection, generateCoverImage, generateInfographic } from './services/geminiService';
import { downloadAsWord } from './services/documentService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessStep>(ProcessStep.IDLE);
  const [content, setContent] = useState<GeneratedContent>({
      section1: '', section2: '', section3: '', section4: ''
  });
  const [userData, setUserData] = useState<UserInputData | null>(null);
  const [hasApiKey, setHasApiKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (window.aistudio) {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(selected);
    }
  };

  const handleApiKeySelect = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      await checkApiKey();
    }
  };

  const handleStartAnalysis = async (data: UserInputData) => {
    if (!hasApiKey && window.aistudio) {
       await handleApiKeySelect();
       const selected = await window.aistudio.hasSelectedApiKey();
       if (!selected) return;
    }

    setUserData(data);
    setStep(ProcessStep.ANALYZING);

    try {
      const fileContext = {
          resume: data.resumeFile, 
          cover: data.coverLetterFile, 
          notice: data.interviewNoticeFile, 
          posting: data.jobPostingFile, 
          preTask: data.preTaskFile,
          ptMaterial: data.ptMaterialFile
      };

      // --- Text Generation Phase ---

      setStep(ProcessStep.WORKFLOW_1);
      const section1 = await generateReportSection(1, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section1 }));

      setStep(ProcessStep.WORKFLOW_2);
      const section2 = await generateReportSection(2, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section2 }));

      setStep(ProcessStep.WORKFLOW_3);
      const section3 = await generateReportSection(3, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section3 }));

      setStep(ProcessStep.WORKFLOW_4);
      const section4 = await generateReportSection(4, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section4 }));

      // --- Image Generation Phase ---
      setStep(ProcessStep.GENERATING_IMAGES);

      // Generate Cover
      const coverImage = await generateCoverImage(data.companyName, data.jobTitle, data.studentName);

      // Generate Infographics (Parallel)
      const [img1, img2, img3, img4] = await Promise.all([
          generateInfographic("Interview Q&A Strategy and Core Competencies"),
          generateInfographic("Crisis Management and Improvisation Strategy"),
          generateInfographic("Applicant SWOT Analysis and Weakness Check"),
          generateInfographic("Interview Attitude and Success Signals")
      ]);

      const finalContent = {
          section1, section2, section3, section4,
          coverImage,
          section1Image: img1,
          section2Image: img2,
          section3Image: img3,
          section4Image: img4
      };

      setContent(finalContent);

      // Completion & Auto Download
      setStep(ProcessStep.COMPLETED);

      // Auto Download
      setTimeout(() => {
          downloadAsWord(finalContent, data);
      }, 1000);

