import { downloadAsWord } from './services/documentService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessStep>(ProcessStep.IDLE);
  const [content, setContent] = useState<GeneratedContent>({
      section1: '', section2: '', section3: '', section4: ''
  });
  const [userData, setUserData] = useState<UserInputData | null>(null);
  const [hasApiKey, setHasApiKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (window.aistudio) {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(selected);
    }
  };

  const handleApiKeySelect = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      await checkApiKey();
    }
  };

  const handleStartAnalysis = async (data: UserInputData) => {
    if (!hasApiKey && window.aistudio) {
       await handleApiKeySelect();
       const selected = await window.aistudio.hasSelectedApiKey();
       if (!selected) return;
    }

    setUserData(data);
    setStep(ProcessStep.ANALYZING);

    try {
      const fileContext = {
          resume: data.resumeFile, 
          cover: data.coverLetterFile, 
          notice: data.interviewNoticeFile, 
          posting: data.jobPostingFile, 
          preTask: data.preTaskFile,
          ptMaterial: data.ptMaterialFile
      };

      // --- Text Generation Phase ---

      setStep(ProcessStep.WORKFLOW_1);
      const section1 = await generateReportSection(1, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section1 }));

      setStep(ProcessStep.WORKFLOW_2);
      const section2 = await generateReportSection(2, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section2 }));

      setStep(ProcessStep.WORKFLOW_3);
      const section3 = await generateReportSection(3, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section3 }));

      setStep(ProcessStep.WORKFLOW_4);
      const section4 = await generateReportSection(4, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section4 }));

      // --- Image Generation Phase ---
      setStep(ProcessStep.GENERATING_IMAGES);

      // Generate Cover
      const coverImage = await generateCoverImage(data.companyName, data.jobTitle, data.studentName);

      // Generate Infographics (Parallel)
      const [img1, img2, img3, img4] = await Promise.all([
          generateInfographic("Interview Q&A Strategy and Core Competencies"),
          generateInfographic("Crisis Management and Improvisation Strategy"),
          generateInfographic("Applicant SWOT Analysis and Weakness Check"),
          generateInfographic("Interview Attitude and Success Signals")
      ]);

      const finalContent = {
