             >
                수동으로 다운로드 (.doc)
             </button>
          </div>
        )}
      </main>

      <footer className="text-center py-10 text-slate-600 text-sm border-t border-white/5">
        &copy; {new Date().getFullYear()} Coaching Pass. All rights reserved.
      </footer>
    </div>
  );
};

