/**
 * Generates a specific section of the interview report.
 */
export const generateReportSection = async (
  sectionIndex: number,
  company: string,
  job: string,
  type: string,
  name: string,
  files: { resume: File | null; cover: File | null; notice: File | null; posting: File | null; preTask: File | null; ptMaterial: File | null }
): Promise<string> => {

  const contentParts: any[] = [];
  const ai = getAiClient();

  try {
    if (files.resume) contentParts.push(await processFile(files.resume));
    if (files.cover) contentParts.push(await processFile(files.cover));
    if (files.notice) contentParts.push(await processFile(files.notice));
    if (files.posting) contentParts.push(await processFile(files.posting));
    if (files.preTask) contentParts.push(await processFile(files.preTask));
    if (files.ptMaterial) contentParts.push(await processFile(files.ptMaterial));
  } catch (validationError) {
    throw validationError;
  }

  let specificPrompt = "";

  switch (sectionIndex) {
    case 1:
      specificPrompt = `
        1. 서류 기반 적중률 높은 예상질문 & 고득점 답변 스크립트 (20문항)
        - 지원자의 서류(이력서, 자소서, 사전과제, PT자료)를 분석하여 예상 질문 20개를 선정.
        - 직무 역량(40%), 인성/협업(30%), 로열티/지원동기(30%) 비율.
        - 질문 의도, 답변 전략, 모범 답변 스크립트 포함.
        - 모범 답변은 구어체로 작성.
      `;
      break;
    case 2:
      specificPrompt = `
        2. 예상치 못한 질문(압박/돌발)이 나왔을 때 임기응변 전략
        - 약점이나 논리적 공백을 파고드는 날카로운 질문 10가지.
        - 쿠션어 사용법, PREP 논리 구조화 화법.
        - 곤란한 상황 대처 매뉴얼.
      `;
      break;
    case 3:
      specificPrompt = `
        3. 면접관 시선에서 지원자님이 꼭 면접 전 대비해야 될 부분 (Checklist & PT Feedback)
        - 서류상 우려 사항 5가지와 해결책.
        - 차별화 포인트(USP) 전략.
        - PT 발표자료가 있다면, 장표 흐름(Storyline), 디자인, 내용 보완점 상세 분석.
      `;
      break;
    case 4:
      specificPrompt = `
        4. 면접장에서 면접관에게 고득점 받을 수 있는 노하우 (Attitude & Formatting)
        - 입장부터 퇴장까지 시뮬레이션.
        - 비언어적 요소(시선, 자세, 목소리).
        - 마지막 할 말 추천 멘트.
      `;
      break;
    default:
      specificPrompt = "면접 솔루션을 작성하세요.";
  }

  const prompt = `
    당신은 대한민국 상위 1% '코칭패스' 수석 컨설턴트입니다.
    지원자 '${name}'의 '${company}' '${job}' 면접 대비를 위한 심층 리포트를 작성 중입니다.

    이번 단계에서는 아래 주제에 대해서만 집중적으로 작성합니다.

    [작성 주제]
    ${specificPrompt}

    [작성 절대 규칙 - 문서 서식 적용]
    문서를 Word 파일로 변환할 때 자동으로 스타일을 입히기 위해 아래 규칙을 반드시 지키세요.

    1. **소제목 (Subheadings)**: 각 질문이나 작은 주제의 제목은 반드시 '###' 으로 시작하세요.
       예) ### 1. 자기소개를 해보세요.
       (이 부분은 문서에서 파란색 텍스트로 변환됩니다.)

    2. **강조 문장 (Warning/Emphasis)**: 답변 전략에서 매우 중요하거나 주의해야 할 핵심 문장은 반드시 '!!' 기호로 감싸세요.
       예) !!절대 하지 말아야 할 것은 핑계를 대는 것입니다.!!
       (이 부분은 문서에서 빨간색 텍스트로 변환됩니다.)

    3. **핵심 키워드 (Bold)**: 중요한 단어나 포인트는 '**' 기호로 감싸세요.
       예) 이 질문의 핵심은 **문제 해결 능력**을 보여주는 것입니다.
       (이 부분은 문서에서 굵은(Bold) 텍스트로 변환됩니다.)

    4. **가독성**: 설명이 길어지면 두 문장마다 줄바꿈을 하세요.
    5. **전문성**: 냉철하고 분석적인 어조.
    6. **분량**: 주제별로 A4 10페이지 분량이 나올 정도로 아주 상세하게 작성하세요.
  `;

  contentParts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', 
      contents: { parts: contentParts },
      config: {
        thinkingConfig: { thinkingBudget: 15000 }, 
      },
    });

    return response.text || "내용 생성 실패";

  } catch (error) {
    console.error(`Section ${sectionIndex} Error:`, error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { InputForm } from './components/InputForm';
import { ProcessVisualizer } from './components/ProcessVisualizer';
import { ProcessStep, UserInputData, GeneratedContent } from './types';
import { generateReportSection, generateCoverImage, generateInfographic } from './services/geminiService';
import { downloadAsWord } from './services/documentService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessStep>(ProcessStep.IDLE);
  const [content, setContent] = useState<GeneratedContent>({
      section1: '', section2: '', section3: '', section4: ''
  });
  const [userData, setUserData] = useState<UserInputData | null>(null);
  const [hasApiKey, setHasApiKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    if (window.aistudio) {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(selected);
    }
  };

  const handleApiKeySelect = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      await checkApiKey();
    }
  };

  const handleStartAnalysis = async (data: UserInputData) => {
    if (!hasApiKey && window.aistudio) {
       await handleApiKeySelect();
       const selected = await window.aistudio.hasSelectedApiKey();
       if (!selected) return;
    }

    setUserData(data);
    setStep(ProcessStep.ANALYZING);

    try {
      const fileContext = {
          resume: data.resumeFile, 
          cover: data.coverLetterFile, 
          notice: data.interviewNoticeFile, 
          posting: data.jobPostingFile, 
          preTask: data.preTaskFile,
          ptMaterial: data.ptMaterialFile
      };

      // --- Text Generation Phase ---

      setStep(ProcessStep.WORKFLOW_1);
      const section1 = await generateReportSection(1, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section1 }));

      setStep(ProcessStep.WORKFLOW_2);
      const section2 = await generateReportSection(2, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section2 }));

      setStep(ProcessStep.WORKFLOW_3);
      const section3 = await generateReportSection(3, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section3 }));

      setStep(ProcessStep.WORKFLOW_4);
      const section4 = await generateReportSection(4, data.companyName, data.jobTitle, data.interviewType, data.studentName, fileContext);
      setContent(prev => ({ ...prev, section4 }));

      // --- Image Generation Phase ---
      setStep(ProcessStep.GENERATING_IMAGES);

      // Generate Cover
      const coverImage = await generateCoverImage(data.companyName, data.jobTitle, data.studentName);

      // Generate Infographics (Parallel) - Using Korean topics to ensure Korean text in images
      const [img1, img2, img3, img4] = await Promise.all([
          generateInfographic("면접 예상 질문 전략 및 핵심 역량"),
          generateInfographic("위기 관리 및 돌발 상황 대처법"),
          generateInfographic("지원자 SWOT 분석 및 약점 체크"),
          generateInfographic("면접 태도 및 합격 시그널")
      ]);

      const finalContent = {
          section1, section2, section3, section4,
          coverImage,
          section1Image: img1,
          section2Image: img2,
          section3Image: img3,
          section4Image: img4
      };

      setContent(finalContent);

      // --- Document Creation Phase ---
      setStep(ProcessStep.CREATING_DOC);

      // Slight delay to allow visualizer to update before download triggers
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Completion & Auto Download
      setStep(ProcessStep.COMPLETED);

      setTimeout(() => {
          downloadAsWord(finalContent, data);
      }, 500);

    } catch (error: any) {
      console.error(error);
      setStep(ProcessStep.ERROR);
      const errorMessage = error instanceof Error ? error.message : "알 수 없는 오류가 발생했습니다.";
      alert(`[오류 발생]\n${errorMessage}\n\n잠시 후 다시 시도하거나, 문제가 지속되면 API Key를 확인해주세요.`);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-slate-200 pb-20 font-sans selection:bg-amber-500/30 selection:text-amber-200">
      {/* Header */}
      <header className="bg-black/80 backdrop-blur-md border-b border-white/10 sticky top-0 z-50 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => window.location.reload()}>
            <div className="w-10 h-10 bg-gradient-to-br from-amber-200 to-amber-600 rounded-xl flex items-center justify-center text-black group-hover:scale-105 transition-transform duration-300 shadow-[0_0_15px_rgba(245,158,11,0.3)]">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
                </svg>
            </div>
            <div className="flex flex-col">
                <h1 className="text-xl font-extrabold text-white tracking-tight leading-none">코칭패스 면접 맞춤 솔루션</h1>
                <span className="text-[10px] font-bold text-amber-500 tracking-[0.2em] uppercase mt-1">Premium Interview Solution</span>
            </div>
          </div>

          <div className="flex items-center space-x-4">
            <button 
                onClick={handleApiKeySelect}
                className="text-xs font-bold text-black bg-amber-500 hover:bg-amber-400 px-4 py-2 rounded-lg transition-colors shadow-[0_0_10px_rgba(245,158,11,0.4)] flex items-center gap-2"
            >
                {hasApiKey ? 'API Key 변경' : 'API Key 설정'}
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-6 py-12">
        {step === ProcessStep.IDLE && (
            <div className="text-center mb-16 animate-fade-in-down">
                <span className="inline-block py-1 px-4 rounded-full bg-amber-900/30 border border-amber-500/30 text-amber-400 text-xs font-bold mb-8 shadow-[0_0_20px_rgba(245,158,11,0.1)]">
                    VVIP 합격 솔루션
                </span>
                <h2 className="text-4xl md:text-5xl lg:text-7xl font-extrabold text-white mb-8 tracking-tight leading-tight">
                    합격의 문을 여는<br/>
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-amber-200 via-amber-400 to-amber-600 drop-shadow-sm">마스터키 (Master Key)</span>
                </h2>
                <p className="text-lg md:text-xl text-slate-400 max-w-2xl mx-auto leading-relaxed font-light">
                    단순한 코칭이 아닙니다.<br className="hidden md:block"/> 
                    <strong className="text-white">코칭패스</strong>는 당신의 서류를 완벽하게 분석하여<br/>
                    면접관을 압도할 수 있는 <span className="text-amber-400">유일무이한 전략</span>을 제시합니다.
                </p>
            </div>
        )}

        {/* Stepper */}
        <div className={`transition-all duration-700 ease-in-out transform ${step === ProcessStep.IDLE ? 'mb-12 translate-y-0 opacity-100' : 'mb-20 translate-y-0 opacity-100'}`}>
          <ProcessVisualizer currentStep={step} />
